import{_ as e,o as t,c as s,a0 as n}from"./chunks/framework.Cl79jK2u.js";const m=JSON.parse('{"title":"Chat Commands","description":"","frontmatter":{},"headers":[],"relativePath":"guide/commands.md","filePath":"guide/commands.md"}'),o={name:"guide/commands.md"};function d(c,a,i,r,p,h){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="chat-commands" tabindex="-1">Chat Commands <a class="header-anchor" href="#chat-commands" aria-label="Permalink to &quot;Chat Commands&quot;">​</a></h1><p>Commands available in Telegram and Slack conversations. All commands start with <code>/</code>.</p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/new [backend] [workspace]</code></td><td>Start a new conversation thread</td></tr><tr><td><code>/model [backend] [model]</code></td><td>Show or switch the agent backend</td></tr><tr><td><code>/think [off|low|medium|high]</code></td><td>Show or set thinking/reasoning effort</td></tr><tr><td><code>/cwd [name|path]</code></td><td>Show or switch working directory</td></tr><tr><td><code>/threads [name]</code></td><td>List or switch threads</td></tr><tr><td><code>/compact</code></td><td>Compact the current thread history</td></tr></tbody></table><h2 id="new" tabindex="-1"><code>/new</code> <a class="header-anchor" href="#new" aria-label="Permalink to &quot;\`/new\`&quot;">​</a></h2><p>Start a fresh conversation thread with an auto-generated name. You can optionally pass a backend or workspace name to switch them at the same time.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new                    → new thread, current backend and cwd stay the same</span></span>
<span class="line"><span>/new codex              → new thread, switch backend to Codex</span></span>
<span class="line"><span>/new myapp              → new thread, switch working directory to &#39;myapp&#39; workspace</span></span>
<span class="line"><span>/new codex myapp        → new thread, switch both</span></span></code></pre></div><h2 id="model" tabindex="-1"><code>/model</code> <a class="header-anchor" href="#model" aria-label="Permalink to &quot;\`/model\`&quot;">​</a></h2><p>Switch the agent backend or model.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model                  → show current backend and model</span></span>
<span class="line"><span>/model codex            → switch to Codex (default model)</span></span>
<span class="line"><span>/model claude opus      → switch to Claude with Opus</span></span>
<span class="line"><span>/model gemini           → switch to Gemini</span></span></code></pre></div><p>If the argument matches a known backend name, the backend switches. Otherwise it&#39;s treated as a model name for the current backend.</p><h2 id="think" tabindex="-1"><code>/think</code> <a class="header-anchor" href="#think" aria-label="Permalink to &quot;\`/think\`&quot;">​</a></h2><p>Control reasoning effort for backends that support it (Claude, Codex, Pi).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/think                  → show current level</span></span>
<span class="line"><span>/think high             → extended thinking</span></span>
<span class="line"><span>/think medium           → balanced</span></span>
<span class="line"><span>/think low              → fast</span></span>
<span class="line"><span>/think off              → disable (default)</span></span></code></pre></div><h2 id="cwd" tabindex="-1"><code>/cwd</code> <a class="header-anchor" href="#cwd" aria-label="Permalink to &quot;\`/cwd\`&quot;">​</a></h2><p>Switch the working directory the agent operates in.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/cwd                    → show current directory</span></span>
<span class="line"><span>/cwd /home/user/project → switch to absolute path</span></span>
<span class="line"><span>/cwd myapp              → switch to named workspace</span></span>
<span class="line"><span>/cwd myapp /path/to/it  → create a named workspace and switch to it</span></span></code></pre></div><p>Named workspaces are saved to the config and persist across restarts.</p><h2 id="threads" tabindex="-1"><code>/threads</code> <a class="header-anchor" href="#threads" aria-label="Permalink to &quot;\`/threads\`&quot;">​</a></h2><p>Manage conversation threads. Threads allow parallel conversations with different contexts.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/threads                → list all threads, current thread marked with &gt;</span></span>
<span class="line"><span>/threads my-feature     → switch to or create thread &quot;my-feature&quot;</span></span></code></pre></div><h2 id="compact" tabindex="-1"><code>/compact</code> <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;\`/compact\`&quot;">​</a></h2><p>Compact the current thread&#39;s history to reduce context size. Useful after long conversations.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact                → compact current thread</span></span></code></pre></div>`,24)])])}const u=e(o,[["render",d]]);export{m as __pageData,u as default};
